import { Box, Button, Container, Divider, Grid, makeStyles, Paper, Typography } from '@material-ui/core'
import axios from 'axios'
import React, { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'

const useStyle = makeStyles(theme => {
    return {
        activity: {
            padding: theme.spacing(2),
            width: '100%'
        },
        btn: {
            marginTop: theme.spacing(2)
        }
    }
})

function StudentActivity() {
    const classes = useStyle()

    const [post, setPost] = useState({});

    const { id } = useParams();
    const getPost = () => {
        const sendData = {
            updateID: id
        };

        axios.post('https://ursacapi.000webhostapp.com/api/getPostID.php', JSON.stringify(sendData))
            .then(response => {
                if (response.data == 0) {
                    console.log('post ID not found');
                } else {
                    setPost(response.data[0]);
                }
            })
    }




    useEffect(() => {
        getPost();
    }, []);

    return (
        <Box>
            <Container>
                <Grid container spacing={2} justifyContent="space-evenly" >
                    <Grid item xs={12} md={6}>
                        <Paper className={classes.activity} elevation={0} square={true} variant='outlined' >
                            <Typography variant='h4' >
                                {post.title}
                            </Typography>


                            <Grid container justifyContent="space-between" >
                                <Grid item>
                                    <Typography variant='caption' >
                                        {post.nameWhoPosted}
                                    </Typography>
                                </Grid>
                                <Grid item>
                                    <Typography variant='caption' >
                                        {post.dateCreated}
                                    </Typography>
                                </Grid>
                            </Grid>




                            <Typography variant='body1' >
                                100 points
                            </Typography>

                            <Divider />

                            <Typography variant='body2' >
                                {post.body}something
                                something asokdjhalkjhsdoihjuawokenm oaisjdlkahjw asjdlkjawlijed askoldjhasdjkljasdj pajoskdikjawioj asopjdoikjasd

                            </Typography>


                        </Paper>
                    </Grid>

                    <Grid item xs={12} md={1}></Grid>

                    <Grid item xs={12} md={5}>
                        <Paper className={classes.activity}>

                        <Grid container justifyContent="space-between" alignContent='center' >
                                <Grid item>
                                    <Typography variant='h6' >
                                        Your work
                                    </Typography>
                                </Grid>
                                <Grid item>
                                    <Typography variant='caption' color='error'  >
                                        Missing
                                    </Typography>
                                </Grid>
                            </Grid>


                            <Button className={classes.btn} color='secondary' variant='outlined' fullWidth >
                                Upload file
                            </Button>

                            <Button className={classes.btn} color='secondary' variant='contained' fullWidth >
                                Submit work
                            </Button>
                        </Paper>
                    </Grid>

                </Grid>

            </Container>
        </Box>
    )
}

export default StudentActivity
